import{_ as a,o,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const f=JSON.parse('{"title":"Profil","description":"","frontmatter":{},"headers":[],"relativePath":"fr/account/profile.md","filePath":"fr/account/profile.md"}'),n={name:"fr/account/profile.md"};function s(r,e,l,c,u,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="profil" tabindex="-1">Profil <a class="header-anchor" href="#profil" aria-label="Permalink to &quot;Profil&quot;">​</a></h1><p>Gerez vos parametres personnels de compte, vos preferences et vos notifications.</p><h2 id="informations-personnelles" tabindex="-1">Informations personnelles <a class="header-anchor" href="#informations-personnelles" aria-label="Permalink to &quot;Informations personnelles&quot;">​</a></h2><p>Mettez a jour votre profil depuis la page <strong>Profil</strong> :</p><ul><li><strong>Nom</strong> -- Votre nom d&#39;affichage</li><li><strong>E-mail</strong> -- Votre adresse e-mail de connexion</li><li><strong>Photo de profil</strong> -- Telechargez une photo ou un avatar</li><li><strong>Langue</strong> -- Langue de l&#39;interface (anglais, neerlandais, allemand, francais)</li></ul><h3 id="changer-de-langue" tabindex="-1">Changer de langue <a class="header-anchor" href="#changer-de-langue" aria-label="Permalink to &quot;Changer de langue&quot;">​</a></h3><ol><li>Allez dans <strong>Profil</strong></li><li>Selectionnez votre langue preferee</li><li>L&#39;interface se met a jour immediatement</li></ol><p>Votre parametre de langue affecte :</p><ul><li>Tous les textes et la navigation de l&#39;interface</li><li>Le formatage des dates et des nombres</li><li>La langue par defaut des nouveaux documents</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>La langue de la facture est definie par facture et peut differer de la langue de votre interface. Vous pouvez envoyer une facture en neerlandais tout en utilisant l&#39;interface en francais.</p></div><h2 id="mot-de-passe" tabindex="-1">Mot de passe <a class="header-anchor" href="#mot-de-passe" aria-label="Permalink to &quot;Mot de passe&quot;">​</a></h2><p>Changez votre mot de passe :</p><ol><li>Allez dans <strong>Profil &gt; Mot de passe</strong></li><li>Entrez votre mot de passe actuel</li><li>Entrez et confirmez votre nouveau mot de passe</li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><p>Si vous vous etes inscrit avec Google ou Microsoft, vous pouvez tout de meme definir un mot de passe pour la connexion par e-mail.</p><h2 id="preferences-de-notification" tabindex="-1">Preferences de notification <a class="header-anchor" href="#preferences-de-notification" aria-label="Permalink to &quot;Preferences de notification&quot;">​</a></h2><p>Controlez quelles notifications vous recevez et comment :</p><h3 id="notifications-par-e-mail" tabindex="-1">Notifications par e-mail <a class="header-anchor" href="#notifications-par-e-mail" aria-label="Permalink to &quot;Notifications par e-mail&quot;">​</a></h3><ul><li><strong>Facture payee</strong> -- Lorsqu&#39;un client paie une facture</li><li><strong>Demande de devis recue</strong> -- Lorsque quelqu&#39;un demande un devis via votre page d&#39;entreprise</li><li><strong>Activite de l&#39;equipe</strong> -- Lorsque des membres de l&#39;equipe effectuent des actions</li><li><strong>Depense approuvee</strong> -- Lorsqu&#39;une depense est approuvee</li></ul><h3 id="resume-par-e-mail" tabindex="-1">Resume par e-mail <a class="header-anchor" href="#resume-par-e-mail" aria-label="Permalink to &quot;Resume par e-mail&quot;">​</a></h3><p>Choisissez la frequence a laquelle vous recevez les e-mails de synthese :</p><ul><li><strong>Quotidien</strong> -- Resume quotidien de l&#39;activite</li><li><strong>Hebdomadaire</strong> -- Recapitulatif de la semaine</li><li><strong>Mensuel</strong> -- Vue d&#39;ensemble mensuelle</li><li><strong>Desactive</strong> -- Pas d&#39;e-mails de synthese</li></ul><h3 id="notifications-push" tabindex="-1">Notifications push <a class="header-anchor" href="#notifications-push" aria-label="Permalink to &quot;Notifications push&quot;">​</a></h3><p>Activez les notifications push du navigateur pour des alertes en temps reel lorsque l&#39;application est ouverte.</p><h3 id="notifications-dans-l-application" tabindex="-1">Notifications dans l&#39;application <a class="header-anchor" href="#notifications-dans-l-application" aria-label="Permalink to &quot;Notifications dans l&#39;application&quot;">​</a></h3><p>Notifications en temps reel dans l&#39;interface MyCompanyDesk. Elles sont toujours actives et apparaissent dans la cloche de notification dans l&#39;en-tete.</p><h2 id="applications-connectees" tabindex="-1">Applications connectees <a class="header-anchor" href="#applications-connectees" aria-label="Permalink to &quot;Applications connectees&quot;">​</a></h2><p>Consultez et gerez les connexions OAuth :</p><ul><li><strong>Google</strong> -- Connecte pour la connexion et/ou l&#39;envoi via Gmail</li><li><strong>Microsoft</strong> -- Connecte pour la connexion et/ou l&#39;envoi via Outlook</li></ul><p>Revoquez l&#39;acces pour deconnecter une application de votre compte.</p>',29)])])}const m=a(n,[["render",s]]);export{f as __pageData,m as default};
